-- ──────────────────────────────────────────────────
-- Migration: 2026_05_18_pr_push_subscriptions_table.sql
-- ──────────────────────────────────────────────────

-- ============================================================================
-- PR push-subs — push_subscriptions table (2026-05-18)
-- ============================================================================
-- Backend writes/reads push_subscriptions in 6 places but the table was
-- never created in the base schema:
--
--   backend/api/push_routes.py:62, 95     (upsert / delete)
--   backend/services/realtime.py:749,     (fan-out reads + 410 cleanup)
--                                  763, 773, 785
--
-- Without this table /api/push/subscribe returns 500 from Supabase and no
-- browser push notification ever reaches a user. Web Push is a paid-tier
-- retention feature so this counts as a launch blocker.
--
-- Schema matches the column set that push_routes.upsert() writes:
--   user_id, endpoint, p256dh, auth, user_agent
-- plus id/created_at/updated_at infra columns. UNIQUE(user_id, endpoint)
-- backs the on_conflict="user_id,endpoint" upsert clause.
--
-- RLS posture (per 2026-05-12 lockdown): RLS enabled, no policies. The
-- frontend never reads this table directly — every interaction goes
-- through /api/push/* which authenticates against service_role. Service
-- role bypasses RLS so backend writes continue unaffected; anon/authed
-- clients are blocked at the row level.
--
-- Idempotent — safe to re-run.
-- ============================================================================

CREATE TABLE IF NOT EXISTS public.push_subscriptions (
    id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id     UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
    endpoint    TEXT NOT NULL,
    p256dh      TEXT NOT NULL,
    auth        TEXT NOT NULL,
    user_agent  TEXT,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (user_id, endpoint)
);

CREATE INDEX IF NOT EXISTS push_subscriptions_user_idx
    ON public.push_subscriptions (user_id);

CREATE INDEX IF NOT EXISTS push_subscriptions_endpoint_idx
    ON public.push_subscriptions (endpoint);

-- Reuse the shared updated_at trigger function if it exists; otherwise
-- create a minimal local one. The base schema defines
-- update_updated_at_column() but we guard against fresh-install order.
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_proc WHERE proname = 'update_updated_at_column'
    ) THEN
        CREATE FUNCTION public.update_updated_at_column()
        RETURNS TRIGGER AS $fn$
        BEGIN
            NEW.updated_at = NOW();
            RETURN NEW;
        END;
        $fn$ LANGUAGE plpgsql;
    END IF;
END$$;

DROP TRIGGER IF EXISTS update_push_subscriptions_updated_at
    ON public.push_subscriptions;

CREATE TRIGGER update_push_subscriptions_updated_at
    BEFORE UPDATE ON public.push_subscriptions
    FOR EACH ROW
    EXECUTE FUNCTION public.update_updated_at_column();

ALTER TABLE public.push_subscriptions ENABLE ROW LEVEL SECURITY;

INSERT INTO public.schema_migrations (version, description)
VALUES (
    '2026_05_18_pr_push_subscriptions_table',
    'Add push_subscriptions table for Web Push fan-out (push_routes + realtime).'
) ON CONFLICT (version) DO NOTHING;


-- ──────────────────────────────────────────────────
-- Migration: 2026_05_24_pr_f_user_strategies.sql
-- ──────────────────────────────────────────────────

-- PR-F: Strategy registry table per v2 design spec §7.3 + §7.5
--
-- One row per saved strategy (template or user-created). Lifecycle:
--   draft   → only authored, never run
--   backtest → run through ml/backtest/engine.py on demand
--   paper   → scheduler runs every N minutes, executes against
--             paper_trades table (no broker)
--   live    → scheduler runs every N minutes, executes against
--             trades table via TradeExecutionService (real broker)
--   paused  → live or paper, suspended without losing config
--
-- The state machine transitions are enforced in code
-- (backend/ai/strategy/registry.py), NOT via DB triggers — keep the
-- DB dumb so we can audit + tune transition rules in Python.
--
-- RLS: SELECT/INSERT/UPDATE/DELETE on own rows; SUPER_ADMIN full access.

BEGIN;

CREATE TABLE IF NOT EXISTS public.user_strategies (
    id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id           UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
    -- Identity + display
    name              TEXT NOT NULL,
    description       TEXT,
    template_slug     TEXT,                 -- non-null if derived from a strategy_catalog row
    -- The DSL document, stored verbatim as JSONB. Pydantic owns the schema.
    dsl               JSONB NOT NULL,
    -- Lifecycle state machine
    status            TEXT NOT NULL DEFAULT 'draft'
                      CHECK (status IN ('draft', 'backtest', 'paper', 'live', 'paused', 'archived')),
    -- Capital allocation when running paper/live
    capital_allocated NUMERIC(15, 2) DEFAULT 0 CHECK (capital_allocated >= 0),
    -- Last backtest summary (denormalized so /strategies list is one query)
    last_backtest     JSONB DEFAULT '{}'::jsonb,
    -- Running statistics (updated by scheduler tick)
    runtime_stats     JSONB DEFAULT '{}'::jsonb,
    -- Ownership origin: user-created via Studio, or seeded from library
    source            TEXT NOT NULL DEFAULT 'user'
                      CHECK (source IN ('user', 'studio', 'template')),
    -- Audit timestamps
    created_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    last_run_at       TIMESTAMPTZ,
    deployed_at       TIMESTAMPTZ,
    paused_at         TIMESTAMPTZ,
    archived_at       TIMESTAMPTZ
);

CREATE INDEX IF NOT EXISTS user_strategies_user_id_idx
    ON public.user_strategies (user_id);

CREATE INDEX IF NOT EXISTS user_strategies_status_idx
    ON public.user_strategies (status)
    WHERE status IN ('paper', 'live');

-- Updated-at trigger so we don't rely on app code remembering
CREATE OR REPLACE FUNCTION public._user_strategies_set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS user_strategies_updated_at ON public.user_strategies;
CREATE TRIGGER user_strategies_updated_at
    BEFORE UPDATE ON public.user_strategies
    FOR EACH ROW EXECUTE FUNCTION public._user_strategies_set_updated_at();

-- RLS — single user can only see their own rows. SUPER_ADMIN bypasses.
ALTER TABLE public.user_strategies ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS user_strategies_own_select ON public.user_strategies;
CREATE POLICY user_strategies_own_select
    ON public.user_strategies
    FOR SELECT
    USING (auth.uid() = user_id);

DROP POLICY IF EXISTS user_strategies_own_modify ON public.user_strategies;
CREATE POLICY user_strategies_own_modify
    ON public.user_strategies
    FOR ALL
    USING (auth.uid() = user_id)
    WITH CHECK (auth.uid() = user_id);

-- Strategy execution log — append-only audit of every scheduler tick
-- that emitted (or considered emitting) an order from a strategy.
CREATE TABLE IF NOT EXISTS public.strategy_executions (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    strategy_id     UUID NOT NULL REFERENCES public.user_strategies(id) ON DELETE CASCADE,
    user_id         UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
    tick_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    symbol          TEXT,
    -- 'entry' / 'exit' / 'no_action'
    decision        TEXT NOT NULL CHECK (decision IN ('entry', 'exit', 'no_action')),
    -- Engine + rule trace for debugging — which condition fired, with values
    trace           JSONB DEFAULT '{}'::jsonb,
    -- Linked trade row if decision != no_action
    trade_id        UUID,
    -- Live or paper at tick time (matches user_strategies.status)
    mode            TEXT NOT NULL CHECK (mode IN ('paper', 'live'))
);

CREATE INDEX IF NOT EXISTS strategy_executions_strategy_id_idx
    ON public.strategy_executions (strategy_id, tick_at DESC);

ALTER TABLE public.strategy_executions ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS strategy_executions_own_select ON public.strategy_executions;
CREATE POLICY strategy_executions_own_select
    ON public.strategy_executions
    FOR SELECT
    USING (auth.uid() = user_id);

COMMIT;


-- ──────────────────────────────────────────────────
-- Migration: 2026_05_28_pru_subscription_plans_seed.sql
-- ──────────────────────────────────────────────────

-- ============================================================================
-- PR-U (2026-05-28) — Align subscription_plans seed with locked 3-tier model.
--
-- complete_schema.sql:82-89 still seeds Free / Starter / Pro at
-- ₹0 / ₹499 / ₹1,499 and then DELETEs any row named 'elite'. This
-- contradicts:
--   * the user_profiles.tier CHECK constraint added in
--     2026_04_19_pr2_v1_ai_stack.sql:33 (tier IN ('free','pro','elite'))
--   * the locked tier model captured in memory
--     project_tier_model_locked_2026_05_28.md
--     (Free ₹0 / Pro ₹999 / Elite ₹1,999)
--   * the frontend STATIC_PLANS in app/pricing/page.tsx:83-132
--
-- The drift hasn't broken production because payment_routes.py:334-360
-- defensively pattern-matches plan names ("elite" in name → elite,
-- "pro" in name → pro), but a "starter" purchase would map to free —
-- silently downgrading paying users.
--
-- This migration is idempotent. It is safe to re-run.
-- ============================================================================

BEGIN;

-- 1. Insert / update the three canonical rows.
--    Prices in INR paise: ₹0 / ₹999 / ₹1,999 monthly.
--    Annual reflects 20% discount (12× monthly × 0.8) per memory.
INSERT INTO public.subscription_plans (
    name,
    display_name,
    description,
    price_monthly,
    price_quarterly,
    price_yearly,
    max_signals_per_day,
    max_positions,
    max_capital,
    signal_only,
    semi_auto,
    full_auto,
    equity_trading,
    futures_trading,
    options_trading,
    telegram_alerts,
    priority_support,
    api_access,
    sort_order
) VALUES
    ('free',  'Free',  'Paper trade + 1 signal/day. No card required.',
        0, 0, 0,
        1, 1, 500000,
        TRUE,  FALSE, FALSE,  TRUE, FALSE, FALSE,  FALSE, FALSE, FALSE,  1),
    ('pro',   'Pro',   'Real signals, Scanner Lab, Alerts Studio.',
        99900, 269900, 959900,
        -1, 15, -1,
        TRUE,  TRUE,  FALSE,  TRUE, FALSE, FALSE,  TRUE,  FALSE, FALSE,  2),
    ('elite', 'Elite', 'AutoPilot auto-trading + AI SIP + F&O.',
        199900, 539900, 1919900,
        -1, -1, -1,
        TRUE,  TRUE,  TRUE,   TRUE, TRUE,  TRUE,   TRUE,  TRUE,  TRUE,   3)
ON CONFLICT (name) DO UPDATE SET
    display_name        = EXCLUDED.display_name,
    description         = EXCLUDED.description,
    price_monthly       = EXCLUDED.price_monthly,
    price_quarterly     = EXCLUDED.price_quarterly,
    price_yearly        = EXCLUDED.price_yearly,
    max_signals_per_day = EXCLUDED.max_signals_per_day,
    max_positions       = EXCLUDED.max_positions,
    max_capital         = EXCLUDED.max_capital,
    signal_only         = EXCLUDED.signal_only,
    semi_auto           = EXCLUDED.semi_auto,
    full_auto           = EXCLUDED.full_auto,
    equity_trading      = EXCLUDED.equity_trading,
    futures_trading     = EXCLUDED.futures_trading,
    options_trading     = EXCLUDED.options_trading,
    telegram_alerts     = EXCLUDED.telegram_alerts,
    priority_support    = EXCLUDED.priority_support,
    api_access          = EXCLUDED.api_access,
    sort_order          = EXCLUDED.sort_order,
    is_active           = TRUE;

-- 2. Retire the legacy 'starter' row if it slipped in via the old seed.
--    Anyone with an active starter subscription is migrated to 'pro' so
--    they keep their feature set (starter@₹499 → pro@₹999 is a price
--    bump, but no paying-customer claim has surfaced; rather than
--    downgrade silently to free we honour the paid status until renewal).
UPDATE public.user_profiles
SET subscription_plan_id = (SELECT id FROM public.subscription_plans WHERE name = 'pro'),
    tier = 'pro'
WHERE subscription_plan_id = (SELECT id FROM public.subscription_plans WHERE name = 'starter');

DELETE FROM public.subscription_plans WHERE name = 'starter';

COMMIT;


-- ──────────────────────────────────────────────────
-- Migration: 2026_05_28_prv_observability_tables.sql
-- ──────────────────────────────────────────────────

-- ============================================================================
-- PR-V (2026-05-28) — Observability persistence layer.
--
-- Two tables that the admin observability surfaces have been quietly
-- depending on, but no migration created them:
--
--   1. analytics_events  — referenced by backend/api/admin/observability.py:100
--      The comment claims PostHog events are "mirrored" here, but no
--      writer existed. PR-V wires the dual-write in posthog_events.track().
--
--   2. llm_usage_events  — new. One row per LLM API call (Copilot,
--      Lab agent, Doctor, debate, ...). Carries model, input/output
--      tokens, and a precomputed micros_usd cost so the cost-per-user
--      rollup on /admin/system can scan a single column.
--
-- Both tables are append-only. They never participate in product reads
-- on the hot path — only admin dashboards + monthly billing rollups.
-- ============================================================================

BEGIN;

-- ─────────────────────────────────────────────────────────────────────────
-- 1. analytics_events — PostHog mirror
-- ─────────────────────────────────────────────────────────────────────────
-- Schema mirrors what backend/api/admin/observability.py:95-114
-- already expects: event TEXT, properties JSONB, ts TIMESTAMPTZ,
-- user_id UUID NULL.

CREATE TABLE IF NOT EXISTS public.analytics_events (
    id          BIGSERIAL PRIMARY KEY,
    event       TEXT        NOT NULL,
    properties  JSONB       NOT NULL DEFAULT '{}'::jsonb,
    user_id     UUID        REFERENCES auth.users(id) ON DELETE SET NULL,
    ts          TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS analytics_events_event_ts_idx
    ON public.analytics_events (event, ts DESC);

CREATE INDEX IF NOT EXISTS analytics_events_user_ts_idx
    ON public.analytics_events (user_id, ts DESC)
    WHERE user_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS analytics_events_ts_idx
    ON public.analytics_events (ts DESC);

-- Service role only — admin reads come through SUPABASE_SERVICE_KEY.
ALTER TABLE public.analytics_events ENABLE ROW LEVEL SECURITY;

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_policies
        WHERE schemaname = 'public'
          AND tablename  = 'analytics_events'
          AND policyname = 'analytics_events_service_only'
    ) THEN
        CREATE POLICY analytics_events_service_only
            ON public.analytics_events
            FOR ALL
            TO service_role
            USING (true)
            WITH CHECK (true);
    END IF;
END $$;

-- ─────────────────────────────────────────────────────────────────────────
-- 2. llm_usage_events — per-call cost log
-- ─────────────────────────────────────────────────────────────────────────
-- One row per LLM API call. ``micros_usd`` is precomputed so the daily
-- cost panel can SUM(micros_usd) WHERE ts > now() - interval '24h' in a
-- single index scan, rather than re-tokenizing.

CREATE TABLE IF NOT EXISTS public.llm_usage_events (
    id              BIGSERIAL PRIMARY KEY,
    user_id         UUID        REFERENCES auth.users(id) ON DELETE SET NULL,
    feature         TEXT        NOT NULL,        -- 'copilot' | 'lab' | 'doctor' | 'debate' | 'finrobot'
    provider        TEXT        NOT NULL,        -- 'anthropic' | 'google' | 'openai'
    model           TEXT        NOT NULL,        -- 'claude-sonnet-4-6', 'gemini-2.5-pro', ...
    input_tokens    INTEGER     NOT NULL DEFAULT 0,
    output_tokens   INTEGER     NOT NULL DEFAULT 0,
    cache_read_tokens  INTEGER  NOT NULL DEFAULT 0,
    cache_write_tokens INTEGER  NOT NULL DEFAULT 0,
    micros_usd      BIGINT      NOT NULL DEFAULT 0,  -- USD * 1_000_000, so 0.000001 USD precision
    latency_ms      INTEGER,
    request_id      TEXT,                            -- provider's request_id when available
    metadata        JSONB       NOT NULL DEFAULT '{}'::jsonb,
    ts              TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS llm_usage_events_user_ts_idx
    ON public.llm_usage_events (user_id, ts DESC)
    WHERE user_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS llm_usage_events_feature_ts_idx
    ON public.llm_usage_events (feature, ts DESC);

CREATE INDEX IF NOT EXISTS llm_usage_events_ts_idx
    ON public.llm_usage_events (ts DESC);

ALTER TABLE public.llm_usage_events ENABLE ROW LEVEL SECURITY;

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_policies
        WHERE schemaname = 'public'
          AND tablename  = 'llm_usage_events'
          AND policyname = 'llm_usage_events_service_only'
    ) THEN
        CREATE POLICY llm_usage_events_service_only
            ON public.llm_usage_events
            FOR ALL
            TO service_role
            USING (true)
            WITH CHECK (true);
    END IF;
END $$;

COMMIT;


-- ──────────────────────────────────────────────────
-- Migration: 2026_05_30_pr_al_strategy_position_stops.sql
-- ──────────────────────────────────────────────────

-- PR-AL — strategy_positions: persist stop_loss / target_1 / exit data
--
-- The strategy runner now sizes positions from the user's capital and
-- enforces a hard SL/target gate (price-based exit) BEFORE evaluating
-- the DSL exit condition. To remember stop/target between ticks we need
-- columns on strategy_positions to persist them at entry time, plus
-- exit_reason + exit_price for closed-position audit.
--
-- Safe to run repeatedly — uses IF NOT EXISTS guards on every ADD.

ALTER TABLE strategy_positions
  ADD COLUMN IF NOT EXISTS stop_loss   DECIMAL(15, 2);
ALTER TABLE strategy_positions
  ADD COLUMN IF NOT EXISTS target_1    DECIMAL(15, 2);
ALTER TABLE strategy_positions
  ADD COLUMN IF NOT EXISTS exit_reason TEXT
    CHECK (exit_reason IS NULL OR exit_reason IN ('stop_loss', 'target', 'dsl_exit', 'manual', 'time'));
ALTER TABLE strategy_positions
  ADD COLUMN IF NOT EXISTS exit_price  DECIMAL(15, 2);

-- Status index helps the runner's per-tick open-position lookup.
CREATE INDEX IF NOT EXISTS idx_strategy_positions_user_status
  ON strategy_positions(user_id, status)
  WHERE status = 'open';


-- ──────────────────────────────────────────────────
-- Migration: 2026_05_30_pr_am_paper_trades_source.sql
-- ──────────────────────────────────────────────────

-- PR-AM — paper_trades.source column
--
-- Adds a ``source`` column so we can tell apart fills the user clicked
-- manually (``manual``) from fills the strategy runner placed on their
-- behalf (``user_strategy``). Useful for activity feeds + analytics
-- ("of your last 100 paper trades, 73 were strategy-fired").
--
-- Backward-compatible: column is nullable, no existing row needs a value.

ALTER TABLE paper_trades
  ADD COLUMN IF NOT EXISTS source TEXT;

CREATE INDEX IF NOT EXISTS idx_paper_trades_user_source_time
  ON paper_trades(user_id, source, executed_at DESC);


-- ──────────────────────────────────────────────────
-- Migration: 2026_05_30_pr_ar_strategy_safety_columns.sql
-- ──────────────────────────────────────────────────

-- PR-AR — strategy safety columns
--
-- Adds the columns needed for:
--   1. Per-strategy day-loss circuit breaker
--   2. Audit trail for why a strategy was paused (manual / loss-breach /
--      reconciliation-error / etc.)
--   3. Daily counters that the breaker reads + the runner increments
--
-- Backward compatible (every ADD uses IF NOT EXISTS; pause_reason is
-- nullable so existing rows stay valid).

ALTER TABLE user_strategies
  ADD COLUMN IF NOT EXISTS max_daily_loss_pct DECIMAL(5, 2);
COMMENT ON COLUMN user_strategies.max_daily_loss_pct IS
  'Per-strategy day-loss breaker. When today''s realized + unrealized P&L on this strategy '
  'drops below this percent of capital deployed, the runner pauses the strategy and skips '
  'further entries. NULL = use the platform default (3%).';

ALTER TABLE user_strategies
  ADD COLUMN IF NOT EXISTS pause_reason TEXT
    CHECK (pause_reason IS NULL OR pause_reason IN
      ('manual', 'day_loss_breach', 'broker_error', 'kill_switch',
       'subscription_lapsed', 'reconciliation_failure'));

-- Reconciliation poller bookkeeping
ALTER TABLE trades
  ADD COLUMN IF NOT EXISTS last_reconciled_at TIMESTAMPTZ;
ALTER TABLE trades
  ADD COLUMN IF NOT EXISTS reconciliation_attempts INT DEFAULT 0;

CREATE INDEX IF NOT EXISTS idx_trades_pending_reconcile
  ON trades(status, last_reconciled_at)
  WHERE status IN ('pending', 'approved');


-- ──────────────────────────────────────────────────
-- Migration: 2026_05_30_pr_at_paper_options.sql
-- ──────────────────────────────────────────────────

-- PR-AT — paper options trading tables
--
-- Multi-leg option positions don't fit the existing paper_positions
-- shape (single symbol, single avg_price). A bull call spread is
-- ONE position to the user (one P&L, one set of risk metrics) but
-- TWO legs in the broker's view (long ATM call + short OTM call).
--
-- Schema:
--   paper_option_positions  — one row per multi-leg position
--   paper_option_legs       — one row per leg (FK to position)
--   paper_option_trades     — entry + exit audit (combined position)
--
-- Both tables get user_id + created_at + status indexes for the
-- runner's open-position sweep and the /strategies/deployed query.

CREATE TABLE IF NOT EXISTS paper_option_positions (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id         UUID NOT NULL,
  strategy_id     UUID,                        -- nullable: ad-hoc deploys allowed
  template_slug   TEXT,                         -- e.g. 'bull_call_spread'
  underlying      TEXT NOT NULL,                -- 'NIFTY', 'BANKNIFTY', 'RELIANCE', ...
  expiry_date     DATE NOT NULL,
  -- Net cost (paid for debit spreads, received for credit spreads).
  -- Positive = we paid premium; negative = we collected.
  net_premium     DECIMAL(15, 2) NOT NULL,
  -- For max loss / margin display on the deployed panel.
  max_profit      DECIMAL(15, 2),
  max_loss        DECIMAL(15, 2),
  -- Pre-trade BS-derived risk metrics; stored for the UI to show
  -- without recomputing every render.
  estimated_margin DECIMAL(15, 2),
  -- Mark-to-market refreshed by the MTM sweep.
  current_value   DECIMAL(15, 2),
  unrealized_pnl  DECIMAL(15, 2),
  realized_pnl    DECIMAL(15, 2),
  status          TEXT NOT NULL DEFAULT 'open'
                  CHECK (status IN ('open', 'closed', 'expired')),
  exit_reason     TEXT CHECK (exit_reason IS NULL OR exit_reason IN
                  ('target', 'stop_loss', 'manual', 'expiry', 'dsl_exit', 'time')),
  entry_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  last_marked_at  TIMESTAMPTZ,
  closed_at       TIMESTAMPTZ,
  metadata        JSONB DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_paper_option_positions_user_status
  ON paper_option_positions(user_id, status);
CREATE INDEX IF NOT EXISTS idx_paper_option_positions_strategy
  ON paper_option_positions(strategy_id) WHERE strategy_id IS NOT NULL;

CREATE TABLE IF NOT EXISTS paper_option_legs (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  position_id     UUID NOT NULL
                  REFERENCES paper_option_positions(id) ON DELETE CASCADE,
  side            TEXT NOT NULL CHECK (side IN ('BUY', 'SELL')),
  option_type     TEXT NOT NULL CHECK (option_type IN ('CE', 'PE')),
  strike          DECIMAL(15, 2) NOT NULL,
  expiry_date     DATE NOT NULL,
  lots            INT NOT NULL CHECK (lots > 0),
  lot_size        INT NOT NULL CHECK (lot_size > 0),
  entry_price     DECIMAL(15, 2) NOT NULL,      -- premium per share at open
  current_price   DECIMAL(15, 2),                -- premium per share at last mark
  exit_price      DECIMAL(15, 2),                -- premium per share at close
  metadata        JSONB DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_paper_option_legs_position
  ON paper_option_legs(position_id);

CREATE TABLE IF NOT EXISTS paper_option_trades (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id         UUID NOT NULL,
  position_id     UUID NOT NULL
                  REFERENCES paper_option_positions(id) ON DELETE CASCADE,
  -- 'open' = position created; 'close' = position closed.
  action          TEXT NOT NULL CHECK (action IN ('open', 'close')),
  -- For close trades, the realized PnL of the entire combined position.
  pnl             DECIMAL(15, 2),
  pnl_pct         DECIMAL(8, 4),
  -- 'manual' | 'user_strategy' | 'mtm_sweep_expired' | 'mtm_sweep_target' | ...
  source          TEXT DEFAULT 'manual',
  executed_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  metadata        JSONB DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_paper_option_trades_user_time
  ON paper_option_trades(user_id, executed_at DESC);


-- ──────────────────────────────────────────────────
-- Migration: 2026_05_30_pr_bf_copilot_conversations.sql
-- ──────────────────────────────────────────────────

-- PR-BF.2 — Saved Copilot conversations
--
-- The /copilot chat surface (PR-AF) renders turns from React state
-- only — refresh and the history is gone. Saving conversations
-- server-side lets users come back to a thread, share it, or have
-- the runner reference past context.
--
-- Schema:
--   copilot_conversations — one row per chat thread
--   copilot_messages      — one row per turn (user OR assistant)
--
-- Idempotent — IF NOT EXISTS on table + indexes.

CREATE TABLE IF NOT EXISTS copilot_conversations (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id     UUID NOT NULL,
  title       TEXT,                         -- derived from first user msg
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  -- Soft-delete so the user can restore; cleaned by a periodic job.
  archived_at TIMESTAMPTZ,
  -- For pinning + free-form tags later.
  metadata    JSONB DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_copilot_conversations_user_updated
  ON copilot_conversations(user_id, updated_at DESC)
  WHERE archived_at IS NULL;

CREATE TABLE IF NOT EXISTS copilot_messages (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  conversation_id UUID NOT NULL
                  REFERENCES copilot_conversations(id) ON DELETE CASCADE,
  -- One of 'user' or 'assistant'. (System prompts aren't persisted —
  -- they live in the orchestrator code and shouldn't drift in DB rows.)
  role            TEXT NOT NULL CHECK (role IN ('user', 'assistant')),
  content         TEXT NOT NULL,
  -- For the assistant turn: which tools the orchestrator called +
  -- the intent classifier's verdict + token counts. Optional.
  tools_used      JSONB DEFAULT '[]'::jsonb,
  trace           JSONB DEFAULT '[]'::jsonb,
  intent          TEXT,
  refused         BOOLEAN DEFAULT FALSE,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_copilot_messages_conversation
  ON copilot_messages(conversation_id, created_at ASC);


-- ──────────────────────────────────────────────────
-- Migration: 2026_05_30_pr_g1_strategy_discovery.sql
-- ──────────────────────────────────────────────────

-- PR-G1 — Strategy Discovery Engine: schema
--
-- Adds two tables:
--   strategy_search_runs    — one row per discovery batch (cron or ad-hoc)
--   discovered_strategies   — per-candidate (rule + backtest stats + score)
--
-- A "run" samples N candidates from a search space (equity_swing,
-- equity_position, fo_weekly, fo_monthly), backtests each on rolling
-- windows, scores them, and persists everything. The user reviews
-- top-K via the Discovered tab and promotes winners to user_strategies.
--
-- LOCKED: candidates are generated by deterministic search over the
-- DSL parameter space (genetic / random / Sobol). NEVER by an LLM —
-- see project_agents_decision_2026_05_10.md.

-- ─── strategy_search_runs ──────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS strategy_search_runs (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),

  -- Search domain. One run targets exactly one of these spaces.
  -- equity_swing    — daily-bar single-instrument or universe, 5-20 day hold
  -- equity_position — daily-bar, 20-90 day hold, fundamentals tilt
  -- fo_weekly       — weekly NSE options, current/next week expiry
  -- fo_monthly      — monthly NSE options, current/next month expiry
  kind            TEXT NOT NULL CHECK (kind IN (
    'equity_swing', 'equity_position', 'fo_weekly', 'fo_monthly'
  )),

  -- Config snapshot — search space definition, sample size, time window,
  -- universe, scoring function. Frozen at run-start so re-runs are
  -- reproducible.
  config          JSONB NOT NULL,

  status          TEXT NOT NULL DEFAULT 'pending'
                  CHECK (status IN ('pending','running','completed','failed','cancelled')),
  error           TEXT,

  -- Lifecycle
  started_at      TIMESTAMPTZ,
  completed_at    TIMESTAMPTZ,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),

  -- Aggregates filled in at completion — saves a JOIN on the list view.
  candidates_total      INTEGER DEFAULT 0,
  candidates_viable     INTEGER DEFAULT 0,   -- passed min_trades + min_sharpe filter
  best_score            NUMERIC(12, 6),
  best_candidate_id     UUID,

  -- Who triggered: null = system cron, non-null = user request.
  triggered_by_user_id  UUID,

  metadata        JSONB DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_strategy_search_runs_kind_started
  ON strategy_search_runs(kind, started_at DESC);
CREATE INDEX IF NOT EXISTS idx_strategy_search_runs_status
  ON strategy_search_runs(status)
  WHERE status IN ('pending', 'running');


-- ─── discovered_strategies ─────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS discovered_strategies (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  run_id          UUID NOT NULL
                  REFERENCES strategy_search_runs(id) ON DELETE CASCADE,

  -- Auto-generated human-readable label. Composed by the runner from the
  -- candidate's key knobs (e.g. "RSI(14)<30 + Mood>0.2 [bull-only]").
  label           TEXT NOT NULL,

  -- Same kind as the parent run — duplicated for fast filtering.
  kind            TEXT NOT NULL CHECK (kind IN (
    'equity_swing', 'equity_position', 'fo_weekly', 'fo_monthly'
  )),

  -- The full Strategy DSL document the user would promote. Validated
  -- through backend.ai.strategy.dsl.Strategy.model_validate at insert
  -- time (via the API layer), so we never persist a broken DSL.
  dsl             JSONB NOT NULL,

  -- ─── Scoring ────────────────────────────────────────────────────────
  -- Primary composite score used for the leaderboard. Higher = better.
  -- Formula lives in the evaluator; usually a blend of net Sharpe,
  -- profit factor, and a stability penalty across regimes.
  score           NUMERIC(12, 6) NOT NULL,

  -- Decomposition — same fields exposed in the UI so the user can sort
  -- by what they care about.
  sharpe          NUMERIC(10, 4),
  calmar          NUMERIC(10, 4),
  max_drawdown_pct NUMERIC(10, 4),
  win_rate        NUMERIC(6, 4),
  profit_factor   NUMERIC(10, 4),
  total_return_pct NUMERIC(12, 4),
  trade_count     INTEGER,
  avg_hold_days   NUMERIC(8, 2),

  -- Per-regime scoring breakdown ({bull: 1.8, sideways: 0.4, bear: -0.2}).
  -- Used by the stability filter — a strategy that only works in one
  -- regime is risky; we surface that in the UI as a "regime concentration"
  -- warning.
  regime_scores   JSONB DEFAULT '{}'::jsonb,

  -- Walk-forward window stats: list of per-fold scores so the user can
  -- see if the strategy decayed (e.g. 2.1 → 1.7 → 0.4 → -0.1) or was
  -- consistent. Empty when single-window backtest.
  walk_forward    JSONB DEFAULT '[]'::jsonb,

  -- Lineage — when the GA mutates a parent into a child, we record it
  -- for inspection ("this strategy descends from candidate X with mutated
  -- RSI threshold").
  parent_id       UUID REFERENCES discovered_strategies(id) ON DELETE SET NULL,
  generation      INTEGER DEFAULT 0,

  -- Lifecycle: candidate → promoted (user pushed to user_strategies) →
  -- archived (user dismissed) → failed (eval errored).
  status          TEXT NOT NULL DEFAULT 'candidate'
                  CHECK (status IN ('candidate','promoted','archived','failed')),
  promoted_to_strategy_id UUID,   -- FK-like: user_strategies.id
  promoted_at     TIMESTAMPTZ,
  promoted_by_user_id     UUID,

  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Leaderboard query: by run, by score DESC.
CREATE INDEX IF NOT EXISTS idx_discovered_strategies_run_score
  ON discovered_strategies(run_id, score DESC);

-- Cross-run leaderboard for a kind: "top swing strategies discovered ever".
CREATE INDEX IF NOT EXISTS idx_discovered_strategies_kind_score
  ON discovered_strategies(kind, score DESC)
  WHERE status = 'candidate';

-- For the promotion review UI ("my promoted strategies").
CREATE INDEX IF NOT EXISTS idx_discovered_strategies_promoted
  ON discovered_strategies(promoted_by_user_id, promoted_at DESC)
  WHERE status = 'promoted';


-- ──────────────────────────────────────────────────
-- Migration: 2026_05_31_pr_s6_saved_scans.sql
-- ──────────────────────────────────────────────────

-- PR-S6 — Saved Scans + Alerts
--
-- Lets a trader save a screener configuration once, have it auto-run on
-- a schedule during market hours, and get notified when new symbols
-- match. Two tables:
--
--   saved_scans          one row per saved configuration
--   saved_scan_alerts    one row per fire — captures the symbol diff
--                        (new hits since last run) for notification

-- ─── saved_scans ──────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS saved_scans (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id         UUID NOT NULL,

  -- User-facing label, e.g. "Power Setup on Nifty 500 Banking"
  name            TEXT NOT NULL CHECK (char_length(name) BETWEEN 1 AND 120),

  -- Which scanners to combine (confluence mode) OR which single
  -- scanner to run. Single-element list = single scanner.
  scanner_ids     INTEGER[] NOT NULL CHECK (array_length(scanner_ids, 1) >= 1),

  -- Optional filters applied BEFORE confluence
  universe        TEXT NOT NULL DEFAULT 'nifty500'
                  CHECK (universe IN ('nifty50','nifty100','nifty500','nse_all')),
  sectors         TEXT[] DEFAULT '{}',         -- canonical sector names
  min_hits        INTEGER NOT NULL DEFAULT 1 CHECK (min_hits BETWEEN 1 AND 10),

  -- Schedule: how often to re-run while market is open.
  --   * 'hourly' → every hour 9:30-15:30 IST Mon-Fri
  --   * 'open_close' → 9:30 + 15:25 only (most economical)
  --   * 'every_15min' → market hours, every 15 min (most aggressive)
  --   * 'manual' → user fires it from the UI; no cron
  schedule        TEXT NOT NULL DEFAULT 'hourly'
                  CHECK (schedule IN ('hourly','open_close','every_15min','manual')),

  -- How to notify on new hits
  notify_channels TEXT[] NOT NULL DEFAULT '{push}'
                  CHECK (notify_channels <@ ARRAY['push','email','whatsapp','telegram']),

  -- Lifecycle
  enabled         BOOLEAN NOT NULL DEFAULT TRUE,
  last_run_at     TIMESTAMPTZ,
  last_hit_symbols TEXT[] DEFAULT '{}',        -- previous run's matches (for diff)
  last_hit_count  INTEGER DEFAULT 0,

  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_saved_scans_user
  ON saved_scans(user_id, created_at DESC);

-- For the cron sweep: pick all enabled scans due for a re-run.
CREATE INDEX IF NOT EXISTS idx_saved_scans_enabled_schedule
  ON saved_scans(enabled, schedule, last_run_at)
  WHERE enabled = TRUE;


-- ─── saved_scan_alerts ────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS saved_scan_alerts (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  scan_id         UUID NOT NULL REFERENCES saved_scans(id) ON DELETE CASCADE,
  user_id         UUID NOT NULL,

  -- Which symbols are NEW since the last run (the diff that triggered
  -- the alert). Not all symbols matched — only the additions, so users
  -- don't get re-alerted for the same hits every hour.
  new_symbols     TEXT[] NOT NULL,
  total_match_count INTEGER NOT NULL DEFAULT 0,

  -- Notification dispatch state
  notified        BOOLEAN NOT NULL DEFAULT FALSE,
  notify_error    TEXT,

  fired_at        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_saved_scan_alerts_user_fired
  ON saved_scan_alerts(user_id, fired_at DESC);

CREATE INDEX IF NOT EXISTS idx_saved_scan_alerts_undelivered
  ON saved_scan_alerts(notified, fired_at)
  WHERE notified = FALSE;


-- ──────────────────────────────────────────────────
-- Migration: 2026_05_31_pr_t1_1_broker_stops.sql
-- ──────────────────────────────────────────────────

-- T1.1 (2026-05-31) — universal broker-side stop tracking.
--
-- Catastrophic-gap fix: previously execution.py only attempted GTT
-- placement for Zerodha and never recorded whether the broker
-- actually accepted the stop. Upstox + Angel positions ran with NO
-- broker-side protection. Now every position carries:
--   - stop_status     'placed' | 'unsupported' | 'failed' | 'unprotected'
--   - stop_broker_id  the GTT/SL-M order id at the broker
--   - target_broker_id  for Zerodha OCO two-leg GTTs
--   - stop_method     'gtt_oco' | 'gtt_single' | 'sl_m'
--   - stop_error      diagnostic on non-'placed' status
--
-- All columns nullable + default NULL so existing positions are
-- unaffected. New positions opened by execution.py:execute_live_trade
-- populate them via stop_orchestrator.StopResult.to_position_patch().

ALTER TABLE positions
  ADD COLUMN IF NOT EXISTS stop_status      TEXT,
  ADD COLUMN IF NOT EXISTS stop_broker_id   TEXT,
  ADD COLUMN IF NOT EXISTS target_broker_id TEXT,
  ADD COLUMN IF NOT EXISTS stop_method      TEXT,
  ADD COLUMN IF NOT EXISTS stop_error       TEXT;

-- Enum-like guard. Use CHECK to keep insert paths honest without
-- needing a Postgres ENUM type (those are painful to evolve).
ALTER TABLE positions
  DROP CONSTRAINT IF EXISTS positions_stop_status_check;
ALTER TABLE positions
  ADD CONSTRAINT positions_stop_status_check
  CHECK (stop_status IS NULL OR stop_status IN (
    'placed', 'unsupported', 'failed', 'unprotected'
  ));

-- Operational index for "find all live positions without broker stop"
-- — this powers the alert that nudges users when their bot opened
-- a position the broker didn't accept the stop for.
CREATE INDEX IF NOT EXISTS positions_unprotected_idx
  ON positions (user_id, stop_status)
  WHERE is_active = TRUE AND stop_status IN ('unprotected', 'failed');


