DROP TABLE IF EXISTS public.gemini_call_log;


-- ──────────────────────────────────────────────────
-- Migration: 2026_06_04_pr_harden_trigger_functions.sql
-- ──────────────────────────────────────────────────

-- ============================================================================
-- 2026-06-04 — Harden trigger functions (Supabase advisor: WARN).
--
--   * function_search_path_mutable (x4): handle_new_user,
--     _user_strategies_set_updated_at, update_updated_at, update_user_stats had
--     no pinned search_path → search-path injection risk (esp. the SECURITY
--     DEFINER one). All four bodies use fully-qualified public.* refs (or none),
--     so SET search_path = '' is safe and is the recommended fix.
--   * "Public can execute SECURITY DEFINER function": handle_new_user is
--     SECURITY DEFINER and EXECUTE-able by anon/authenticated/public. It is a
--     trigger fired on auth.users INSERT — the trigger runs it regardless of
--     direct EXECUTE grants, so revoking EXECUTE is safe and closes the finding.
--     (Same for the other trigger fns — they are never called directly.)
--
-- Idempotent.
-- ============================================================================

ALTER FUNCTION public.handle_new_user()                 SET search_path = '';
ALTER FUNCTION public._user_strategies_set_updated_at() SET search_path = '';
ALTER FUNCTION public.update_updated_at()               SET search_path = '';
ALTER FUNCTION public.update_user_stats()               SET search_path = '';

REVOKE EXECUTE ON FUNCTION public.handle_new_user()                 FROM anon, authenticated, PUBLIC;
REVOKE EXECUTE ON FUNCTION public._user_strategies_set_updated_at() FROM anon, authenticated, PUBLIC;
REVOKE EXECUTE ON FUNCTION public.update_updated_at()               FROM anon, authenticated, PUBLIC;
REVOKE EXECUTE ON FUNCTION public.update_user_stats()               FROM anon, authenticated, PUBLIC;


-- ──────────────────────────────────────────────────
-- Migration: 2026_06_04_pr_lock_legacy_exposed_tables.sql
-- ──────────────────────────────────────────────────

-- ============================================================================
-- 2026-06-04 — Lock 26 legacy "exposed" tables to service-role-only.
--
-- Audit (frontend supabase-js + backend anon client) found the app reads only
-- 4 tables via the anon/authenticated role: user_profiles, strategy_catalog,
-- strategy_backtests, user_strategy_deployments. The other 26 carried anon/
-- authenticated/public RLS policies from an earlier design where the frontend
-- read tables directly — but the app now reads them via the FastAPI service key.
--
-- Worse, several had `USING (true) TO public` policies — i.e. WORLD read (and
-- some world write/delete) of USER data once populated:
--   portfolio_doctor_reports, user_autopilot_streams, research_reports,
--   user_ai_overlay_settings (user data); model_rolling_performance,
--   regime_history (global, non-user).
--
-- This converts all 26 to service-role-only: drop the permissive policies,
-- ensure RLS + a service_role policy, revoke anon/authenticated grants. Safe —
-- service_role bypasses RLS, and none of the 26 are read via anon/authenticated.
-- The 4 genuinely-used tables are intentionally NOT in this list.
--
-- Idempotent.
-- ============================================================================

DO $$
DECLARE
    t   text;
    pol record;
    tbls text[] := ARRAY[
        'ai_portfolio_holdings','auto_trader_runs','model_rolling_performance','notifications',
        'paper_portfolios','paper_positions','paper_snapshots','paper_trades','payments',
        'portfolio_doctor_reports','portfolio_history','positions','regime_history',
        'research_reports','signals','strategy_executions','strategy_outcomes','strategy_positions',
        'trades','user_ai_overlay_settings','user_autopilot_streams','user_digest_deliveries',
        'user_referrals','user_strategies','user_weekly_reviews','watchlist'
    ];
BEGIN
    FOREACH t IN ARRAY tbls LOOP
        IF EXISTS (SELECT 1 FROM pg_tables WHERE schemaname='public' AND tablename=t) THEN
            -- drop every policy that grants anon/authenticated/public
            FOR pol IN
                SELECT policyname FROM pg_policies
                WHERE schemaname='public' AND tablename=t
                  AND roles && ARRAY['anon','authenticated','public']::name[]
            LOOP
                EXECUTE format('DROP POLICY %I ON public.%I;', pol.policyname, t);
            END LOOP;

            EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY;', t);

            IF NOT EXISTS (
                SELECT 1 FROM pg_policies
                WHERE schemaname='public' AND tablename=t
                  AND policyname = t || '_service_only'
            ) THEN
                EXECUTE format(
                    'CREATE POLICY %I ON public.%I FOR ALL TO service_role '
                    'USING (true) WITH CHECK (true);',
                    t || '_service_only', t
                );
            END IF;

            EXECUTE format('REVOKE ALL ON public.%I FROM anon, authenticated;', t);
        END IF;
    END LOOP;
END $$;


-- ──────────────────────────────────────────────────
-- Migration: 2026_06_04_pr_revoke_api_grants_backend_tables.sql
-- ──────────────────────────────────────────────────

-- ============================================================================
-- 2026-06-04 — Revoke anon/authenticated API grants on backend-only objects.
--
-- Supabase advisor (WARN): "Public/Signed-In Users Can See Object in GraphQL
-- Schema". anon/authenticated held table-level grants on backend-only objects,
-- so they appeared in the auto-generated PostgREST/GraphQL API surface (object
-- NAMES discoverable; data already blocked by RLS).
--
-- We revoke ONLY where it is provably safe: tables that have RLS enabled AND no
-- policy permitting anon/authenticated/public — i.e. anon/authenticated already
-- get zero rows, so removing their grant changes no behaviour, it just drops
-- them from the API surface. Tables WITH an anon/authenticated policy
-- (user_profiles, strategy_catalog, strategy_backtests, user_strategy_deployments,
-- and the other intentionally-exposed tables) are left untouched — the app
-- reads those via the Supabase API. The two orphan (security_invoker) views are
-- also revoked since nothing reads them.
--
-- Dynamic + idempotent: only ever targets service-locked tables.
-- ============================================================================

DO $$
DECLARE r record;
BEGIN
    FOR r IN
        SELECT c.relname
        FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
        WHERE n.nspname = 'public' AND c.relkind = 'r' AND c.relrowsecurity
          AND NOT EXISTS (
              SELECT 1 FROM pg_policies p
              WHERE p.schemaname = 'public' AND p.tablename = c.relname
                AND p.roles && ARRAY['anon','authenticated','public']::name[]
          )
    LOOP
        EXECUTE format('REVOKE ALL ON public.%I FROM anon, authenticated;', r.relname);
    END LOOP;

    -- Orphan security-invoker views (unreferenced by app code).
    EXECUTE 'REVOKE ALL ON public.v_user_stats   FROM anon, authenticated';
    EXECUTE 'REVOKE ALL ON public.v_today_signals FROM anon, authenticated';
END $$;


-- ──────────────────────────────────────────────────
-- Migration: 2026_06_04_pr_rls_enable_orphan_tables.sql
-- ──────────────────────────────────────────────────

-- ============================================================================
-- 2026-06-04 — Enable RLS on 16 previously-unprotected tables.
--
-- Supabase advisor flagged these with Row Level Security DISABLED, i.e. fully
-- exposed to the anon + authenticated roles (anyone with the anon key could
-- read/modify every row — including user chat data in copilot_conversations /
-- copilot_messages).
--
-- The frontend reaches NONE of these directly — it uses Supabase only for auth
-- (auth.getUser/getSession); all table access goes through the FastAPI backend
-- with the service key. service_role BYPASSES RLS, so enabling RLS + a
-- service_role-only policy closes the hole without breaking any code path.
-- (Same pattern as analytics_events / llm_usage_events in the PR-V migration.)
--
-- If any of these later needs a DIRECT authenticated frontend read, add a
-- per-table owner policy (e.g. USING (auth.uid() = user_id)) at that point.
--
-- Idempotent: ENABLE RLS is a no-op if already on; policies are guarded.
-- ============================================================================

DO $$
DECLARE
    t text;
    tbls text[] := ARRAY[
        'strategy_runner_runs', 'tick_data', 'tick_collector_runs',
        'paper_option_positions', 'paper_option_legs', 'paper_option_trades',
        'copilot_conversations', 'copilot_messages', 'strategy_search_runs',
        'discovered_strategies', 'saved_scans', 'saved_scan_alerts',
        'scanner_outcomes', 'scanner_stats', 'system_cron_runs',
        'autopilot_track_record_daily'
    ];
BEGIN
    FOREACH t IN ARRAY tbls LOOP
        EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY;', t);
        IF NOT EXISTS (
            SELECT 1 FROM pg_policies
            WHERE schemaname = 'public'
              AND tablename  = t
              AND policyname = t || '_service_only'
        ) THEN
            EXECUTE format(
                'CREATE POLICY %I ON public.%I FOR ALL TO service_role '
                'USING (true) WITH CHECK (true);',
                t || '_service_only', t
            );
        END IF;
    END LOOP;
END $$;


-- ──────────────────────────────────────────────────
-- Migration: 2026_06_04_pr_rls_policies_backend_tables.sql
-- ──────────────────────────────────────────────────

-- ============================================================================
-- 2026-06-04 — Add service_role policies to RLS-enabled / no-policy tables.
--
-- These tables had RLS ENABLED but ZERO policies (Supabase advisor: "RLS
-- Enabled No Policy"). That state is already SAFE — with no policy, anon/
-- authenticated are fully blocked, and the backend (service_role) bypasses RLS.
-- But the advisor flags it as possibly-unintentional. Adding an explicit
-- service_role-only policy documents intent and clears the note WITHOUT
-- changing access (service_role bypasses RLS regardless; anon/authenticated
-- stay blocked). The frontend never reads these directly (it only reads
-- user_profiles), and the backend reads them via the service key.
--
-- Idempotent.
-- ============================================================================

DO $$
DECLARE
    t text;
    tbls text[] := ARRAY[
        'admin_audit_log', 'alpha_scores', 'audit_log', 'broker_connections',
        'candles', 'daily_universe', 'earnings_predictions', 'eod_scan_runs',
        'features', 'forecast_scores', 'market_data', 'model_outcomes',
        'model_performance', 'model_versions', 'news_sentiment',
        'scheduler_job_runs', 'schema_migrations', 'signal_debates', 'stocks',
        'subscription_plans', 'system_flags', 'training_runs', 'vix_forecasts'
    ];
BEGIN
    FOREACH t IN ARRAY tbls LOOP
        -- skip any table that doesn't exist (defensive)
        IF EXISTS (SELECT 1 FROM pg_tables WHERE schemaname='public' AND tablename=t) THEN
            EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY;', t);
            IF NOT EXISTS (
                SELECT 1 FROM pg_policies
                WHERE schemaname='public' AND tablename=t
                  AND policyname = t || '_service_only'
            ) THEN
                EXECUTE format(
                    'CREATE POLICY %I ON public.%I FOR ALL TO service_role '
                    'USING (true) WITH CHECK (true);',
                    t || '_service_only', t
                );
            END IF;
        END IF;
    END LOOP;
END $$;


-- ──────────────────────────────────────────────────
-- Migration: 2026_06_04_pr_secure_definer_views.sql
-- ──────────────────────────────────────────────────

-- ============================================================================
-- 2026-06-04 — Fix SECURITY DEFINER views (Supabase advisor: ERROR).
--
-- public.v_user_stats and public.v_today_signals were created as SECURITY
-- DEFINER views owned by `postgres`, and anon/authenticated hold SELECT on
-- them. A SECURITY DEFINER view runs with the OWNER's privileges, so those
-- roles could read through the views and BYPASS RLS on the underlying tables —
-- exposing every user's capital / total_pnl / win-rate (v_user_stats) and the
-- full signal feed (v_today_signals) to anyone with the anon key.
--
-- Neither view is referenced by application code (legacy orphans from
-- FULL_SETUP.sql). Switching them to SECURITY INVOKER makes them respect the
-- CALLER's RLS: anon/authenticated now see only what RLS permits (nothing,
-- for cross-user rows), while the backend (service_role) keeps full access
-- since service_role bypasses RLS regardless.
--
-- Idempotent: SET (security_invoker = on) is a safe no-op if already set.
-- ============================================================================

ALTER VIEW public.v_user_stats    SET (security_invoker = on);
ALTER VIEW public.v_today_signals SET (security_invoker = on);


-- ──────────────────────────────────────────────────
-- Migration: 2026_06_04_pr_system_cron_runs_table.sql
-- ──────────────────────────────────────────────────

-- ============================================================================
-- 2026-06-04 — system_cron_runs: cron idempotency ledger (migration was missing).
--
-- This table exists in production but had NO migration, so a clean DB rebuild
-- (fresh install from complete_schema.sql) would silently omit it — and with it
-- the load-bearing UNIQUE(job_id, run_date) constraint that prevents a daily
-- cron (e.g. the AutoPilot rebalance that places real trades) from double-firing
-- if two scheduler instances run or a job is retried within the same day.
--
-- Mirrors the live prod schema exactly. Idempotent.
-- ============================================================================

CREATE TABLE IF NOT EXISTS public.system_cron_runs (
    id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    job_id       TEXT        NOT NULL,
    run_date     DATE        NOT NULL,
    started_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    completed_at TIMESTAMPTZ,
    status       TEXT        NOT NULL DEFAULT 'running'
                 CHECK (status IN ('running', 'completed', 'failed', 'skipped')),
    pid          TEXT,
    duration_ms  INTEGER,
    error        TEXT,
    metadata     JSONB       NOT NULL DEFAULT '{}'::jsonb,
    CONSTRAINT system_cron_runs_job_id_run_date_key UNIQUE (job_id, run_date)
);

CREATE INDEX IF NOT EXISTS system_cron_runs_job_date_idx
    ON public.system_cron_runs (job_id, run_date DESC);

-- Backend-only (service_role). Consistent with the other ops/telemetry tables.
ALTER TABLE public.system_cron_runs ENABLE ROW LEVEL SECURITY;
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_policies
        WHERE schemaname='public' AND tablename='system_cron_runs'
          AND policyname='system_cron_runs_service_only'
    ) THEN
        CREATE POLICY system_cron_runs_service_only ON public.system_cron_runs
            FOR ALL TO service_role USING (true) WITH CHECK (true);
    END IF;
END $$;


-- ──────────────────────────────────────────────────
-- Migration: 2026_06_08_pr_f0f1_reference_ohlc.sql
-- ──────────────────────────────────────────────────

-- F0+F1: reference spine + durable EOD OHLC store (free-sourced, backend-only).
-- Part B of complete_schema.sql auto-regenerates from this; do not hand-edit Part B.

-- F0.1 instrument master ------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.instruments (
    symbol TEXT NOT NULL, exchange TEXT NOT NULL DEFAULT 'NSE',
    instrument_type TEXT NOT NULL DEFAULT 'EQ',
    isin TEXT, series TEXT, name TEXT, sector TEXT, mcap_category TEXT,
    lot_size INT, tick_size NUMERIC,
    -- sentinels (NOT NULL DEFAULT) so the composite PK uses plain columns —
    -- Postgres forbids expressions (COALESCE) in a PRIMARY KEY, and the upsert
    -- on_conflict target must match these columns verbatim. Equities omit
    -- expiry/strike on insert → DEFAULTs apply → conflict resolves cleanly.
    strike NUMERIC NOT NULL DEFAULT 0,
    expiry DATE NOT NULL DEFAULT '1900-01-01',
    listing_date DATE, face_value NUMERIC, status TEXT DEFAULT 'active',
    source TEXT DEFAULT 'nselib', updated_at TIMESTAMPTZ DEFAULT NOW(),
    PRIMARY KEY (symbol, exchange, instrument_type, expiry, strike)
);
CREATE INDEX IF NOT EXISTS idx_instruments_symbol ON public.instruments (symbol);

-- F0.2 index constituents -----------------------------------------------------
CREATE TABLE IF NOT EXISTS public.index_constituents (
    index_name TEXT NOT NULL, symbol TEXT NOT NULL, weight NUMERIC,
    industry TEXT, source TEXT DEFAULT 'niftyindices', updated_at TIMESTAMPTZ DEFAULT NOW(),
    PRIMARY KEY (index_name, symbol)
);

-- F0.3 corporate actions ------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.corporate_actions (
    symbol TEXT NOT NULL, ex_date DATE NOT NULL,
    action_type TEXT NOT NULL,
    ratio_from NUMERIC, ratio_to NUMERIC, value NUMERIC, details JSONB,
    source TEXT DEFAULT 'nselib',
    PRIMARY KEY (symbol, ex_date, action_type)
);
CREATE INDEX IF NOT EXISTS idx_corpactions_symbol ON public.corporate_actions (symbol, ex_date DESC);

-- F1 evolve orphan candles -> partitioned daily store-of-record ---------------
-- Idempotent + DATA-PRESERVING. The first version renamed candles aside and then
-- DROPPED it unconditionally, destroying every existing row (prod had 31,200).
-- This version: skip if already partitioned; otherwise rename the existing
-- (non-partitioned) table aside, build the partitioned store, COPY every row
-- forward, then drop the legacy copy. Safe to re-run.
DO $$
BEGIN
    -- Already partitioned (re-run / fresh install already migrated): nothing to do.
    IF EXISTS (
        SELECT 1 FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
        WHERE n.nspname = 'public' AND c.relname = 'candles' AND c.relkind = 'p'
    ) THEN
        RAISE NOTICE 'candles already partitioned; skipping F1 migration';
        RETURN;
    END IF;

    -- Preserve any existing (non-partitioned) candles by renaming it aside.
    IF EXISTS (
        SELECT 1 FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
        WHERE n.nspname = 'public' AND c.relname = 'candles'
    ) THEN
        ALTER TABLE public.candles RENAME TO candles_legacy;
    END IF;

    CREATE TABLE public.candles (
        stock_symbol TEXT NOT NULL, exchange TEXT NOT NULL DEFAULT 'NSE',
        interval TEXT NOT NULL DEFAULT '1d', timestamp TIMESTAMPTZ NOT NULL,
        open NUMERIC, high NUMERIC, low NUMERIC, close NUMERIC, volume BIGINT,
        delivery_qty BIGINT, delivery_pct NUMERIC, adj_close NUMERIC,
        source TEXT NOT NULL DEFAULT 'nselib', created_at TIMESTAMPTZ DEFAULT NOW(),
        PRIMARY KEY (stock_symbol, interval, timestamp)
    ) PARTITION BY RANGE (timestamp);
    CREATE TABLE IF NOT EXISTS public.candles_y2019 PARTITION OF public.candles FOR VALUES FROM ('2019-01-01') TO ('2020-01-01');
    CREATE TABLE IF NOT EXISTS public.candles_y2020 PARTITION OF public.candles FOR VALUES FROM ('2020-01-01') TO ('2021-01-01');
    CREATE TABLE IF NOT EXISTS public.candles_y2021 PARTITION OF public.candles FOR VALUES FROM ('2021-01-01') TO ('2022-01-01');
    CREATE TABLE IF NOT EXISTS public.candles_y2022 PARTITION OF public.candles FOR VALUES FROM ('2022-01-01') TO ('2023-01-01');
    CREATE TABLE IF NOT EXISTS public.candles_y2023 PARTITION OF public.candles FOR VALUES FROM ('2023-01-01') TO ('2024-01-01');
    CREATE TABLE IF NOT EXISTS public.candles_y2024 PARTITION OF public.candles FOR VALUES FROM ('2024-01-01') TO ('2025-01-01');
    CREATE TABLE IF NOT EXISTS public.candles_y2025 PARTITION OF public.candles FOR VALUES FROM ('2025-01-01') TO ('2026-01-01');
    CREATE TABLE IF NOT EXISTS public.candles_y2026 PARTITION OF public.candles FOR VALUES FROM ('2026-01-01') TO ('2027-01-01');
    CREATE TABLE IF NOT EXISTS public.candles_y2027 PARTITION OF public.candles FOR VALUES FROM ('2027-01-01') TO ('2028-01-01');
    -- Catch-all: an out-of-range timestamp in the legacy copy (or a future
    -- ingest) lands here instead of failing the INSERT below.
    CREATE TABLE IF NOT EXISTS public.candles_default PARTITION OF public.candles DEFAULT;
    CREATE INDEX IF NOT EXISTS idx_candles_symbol_time ON public.candles (stock_symbol, timestamp DESC);

    -- Carry every existing row forward (legacy lacks the delivery and adj_close
    -- columns -> NULL; legacy 'id' PK is dropped for the composite key). De-dup
    -- via the new composite PK.
    IF EXISTS (
        SELECT 1 FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
        WHERE n.nspname = 'public' AND c.relname = 'candles_legacy'
    ) THEN
        INSERT INTO public.candles
            (stock_symbol, exchange, interval, timestamp, open, high, low, close, volume, source, created_at)
        SELECT stock_symbol, exchange, interval, timestamp, open, high, low, close, volume, source, created_at
        FROM public.candles_legacy
        ON CONFLICT (stock_symbol, interval, timestamp) DO NOTHING;
        DROP TABLE public.candles_legacy;
    END IF;
END $$;

-- backend-only RLS (no PostgREST exposure) ------------------------------------
ALTER TABLE public.instruments ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.index_constituents ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.corporate_actions ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.candles ENABLE ROW LEVEL SECURITY;
REVOKE ALL ON public.instruments, public.index_constituents, public.corporate_actions, public.candles FROM anon, authenticated;
-- RLS on the partition CHILDREN too: RLS on the partitioned parent does NOT
-- cover direct access to partitions, and Supabase exposes each partition to
-- PostgREST/GraphQL — without this they were anon/authenticated-readable.
ALTER TABLE public.candles_y2019   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.candles_y2020   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.candles_y2021   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.candles_y2022   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.candles_y2023   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.candles_y2024   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.candles_y2025   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.candles_y2026   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.candles_y2027   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.candles_default ENABLE ROW LEVEL SECURITY;
REVOKE ALL ON public.candles_y2019, public.candles_y2020, public.candles_y2021,
  public.candles_y2022, public.candles_y2023, public.candles_y2024,
  public.candles_y2025, public.candles_y2026, public.candles_y2027,
  public.candles_default FROM anon, authenticated;


